class ReproduceHangTest : TestBase() {
    @Test
    fun testHang() = runTest {
        withTimeout(2000) {
            val result = flowOf(1)
                .take(1)
                .onCompletion { if (it == null) awaitCancellation() }
                .first()
            assertEquals(1, result)
        }
    }

