101→    private class FlowTakeCollector<T>(
102→        private val count: Int,
103→        downstream: FlowCollector<T>
104→    ) : FlowCollector<T>, Continuation<Unit> {
105→        private var consumed = 0
106→        // Workaround for KT-30991
107→        private val emitFun = run {
108→            val suspendFun: suspend (T) -> Unit = { downstream.emit(it) }
109→            suspendFun as Function2<T, Continuation<Unit>, Any?>
110→        }
111→
112→        private var caller: Continuation<Unit>? = null // lateinit
113→
114→        override val context: CoroutineContext
115→            get() = caller?.context ?: EmptyCoroutineContext
116→
117→        override fun resumeWith(result: Result<Unit>) {
118→            val completion = caller!!
119→            if (++consumed == count) completion.resumeWith(Result.failure(StacklessCancellationException()))
120→            else completion.resumeWith(Result.success(Unit))
121→        }
122→
123→        override suspend fun emit(value: T) = suspendCoroutineUninterceptedOrReturn<Unit> sc@{
124→            // Invoke it in non-suspending way
125→            caller = it
126→            val result = emitFun.invoke(value, this)
127→            if (result !== COROUTINE_SUSPENDED) {
128→                if (++consumed == count) throw StacklessCancellationException()
129→                else return@sc Unit
130→            }
131→            COROUTINE_SUSPENDED
132→        }
133→    }
134→}
